import React, { useEffect, useRef, useState } from "react";
import { supabase } from "./lib/supabase.js";

// Replace these with your actual base64 strings
const RN_LOGO_BASE64 = "data:image/jpeg;base64,";
const GOOGLE_LOGO_BASE64 = "data:image/png;base64,";

export default function Auth() {
  const canvasRef = useRef(null);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState("");

  // ---------------------------
  // TWINKLING STAR BACKGROUND
  // ---------------------------
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    let stars = [];

    const initStars = () => {
      stars = [];
      for (let i = 0; i < 150; i++) {
        stars.push({
          x: Math.random() * window.innerWidth,
          y: Math.random() * window.innerHeight,
          size: Math.random() * 1.5,
          opacity: Math.random(),
          speed: Math.random() * 0.02
        });
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      stars.forEach(s => {
        s.opacity += s.speed;
        if (s.opacity > 1 || s.opacity < 0) s.speed *= -1;
        ctx.fillStyle = `rgba(255, 255, 255, ${s.opacity})`;
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
        ctx.fill();
      });
      requestAnimationFrame(draw);
    };

    const handleResize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      initStars();
    };

    window.addEventListener("resize", handleResize);
    handleResize();
    draw();
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  // ---------------------------
  // AUTH HANDLERS
  // ---------------------------
  const handleLogin = async () => {
    setLoading(true);
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    setLoading(false);
    if (error) setMsg(error.message);
    else window.location.href = "/";
  };

  const handleSignup = async () => {
    setLoading(true);
    const { error } = await supabase.auth.signUp({ email, password });
    setLoading(false);
    if (error) setMsg(error.message);
    else alert("Check your email to confirm account.");
  };

  const handleGoogle = async () => {
    await supabase.auth.signInWithOAuth({
      provider: "google",
      options: {redirectTo: `${window.location.origin}/auth/callback`}
    });
  };

  return (
    <>
      <canvas ref={canvasRef} className="bg-canvas" />
      
      <div className="auth-container">
        <div className="auth-card">
          <img src={RN_LOGO_BASE64} className="logo" alt="Logo" />
          <h1 className="title">Reuben<span>AI</span></h1>
          <p className="subtitle">SECURE AI AUTHENTICATION PORTAL</p>

          <button className="google-btn" onClick={handleGoogle}>
            <img src={GOOGLE_LOGO_BASE64} className="g-icon" alt="G" />
            Continue with Google
          </button>

          <div className="divider"><span>or use email</span></div>

          <label>Email Address</label>
          <input type="email" placeholder="Enter your email" onChange={(e) => setEmail(e.target.value)} />

          <label>Password</label>
          <div className="password-input">
            <input type={showPassword ? "text" : "password"} placeholder="Enter your password" onChange={(e) => setPassword(e.target.value)} />
            <span onClick={() => setShowPassword(!showPassword)}>👁</span>
          </div>

          {msg && <p style={{ color: '#ff5c5c', fontSize: '12px' }}>{msg}</p>}

          <button className="login-btn" onClick={handleLogin} disabled={loading}>
            {loading ? "LOADING..." : "LOGIN"}
          </button>
          <button className="signup-btn" onClick={handleSignup} disabled={loading}>
            CREATE ACCOUNT
          </button>

          <p className="footer">🔒 Your data is protected with enterprise-grade security</p>
        </div>
      </div>

      <style>{`
        body { margin: 0; }
        .bg-canvas { position: fixed; top:0; left:0; background: #020817; z-index: -1; }
        .auth-container { display: flex; justify-content: center; align-items: center; min-height: 100vh; padding: 20px; box-sizing: border-box; }
        .auth-card { width: 100%; max-width: 450px; max-height: 95vh; overflow-y: auto; padding: 30px; background: rgba(10, 15, 25, 0.8); border: 1px solid #1e293b; border-radius: 20px; color: white; backdrop-filter: blur(10px); }
        .logo { width: 80px; display: block; margin: 0 auto 15px; }
        .title { text-align: center; font-size: 32px; margin: 0; }
        .title span { color: #06b6d4; }
        .subtitle { text-align: center; color: #64748b; font-size: 12px; margin-bottom: 25px; }
        .google-btn { width: 100%; padding: 12px; background: white; border: none; border-radius: 8px; font-weight: bold; display: flex; justify-content: center; align-items: center; gap: 10px; cursor: pointer; color: black; }
        .g-icon { width: 20px; }
        .divider { text-align: center; margin: 20px 0; color: #475569; font-size: 14px; }
        label { display: block; margin-bottom: 5px; font-size: 14px; color: #94a3b8; }
        input { width: 100%; padding: 12px; margin-bottom: 15px; background: #0f172a; border: 1px solid #334155; border-radius: 8px; color: white; box-sizing: border-box; }
        .password-input { position: relative; }
        .password-input span { position: absolute; right: 15px; top: 12px; cursor: pointer; color: #64748b; }
        .login-btn { width: 100%; padding: 12px; background: #06b6d4; border: none; border-radius: 8px; color: black; font-weight: bold; cursor: pointer; margin-bottom: 10px; }
        .signup-btn { width: 100%; padding: 12px; background: transparent; border: 1px solid #334155; border-radius: 8px; color: white; cursor: pointer; }
        .footer { text-align: center; color: #475569; font-size: 11px; margin-top: 20px; }
      `}</style>
    </>
  );
}